const companies = $input.all().map(i => i.json);

// Deduplicate by user_id — keep the latest entry per company
const latestByUser = {};
for (const company of companies) {
  const uid = company.user_id || company.companyid || company.userid;
  if (!uid) continue;
  if (!latestByUser[uid] || company.id > latestByUser[uid].id) {
    latestByUser[uid] = company;
  }
}
const unique = Object.values(latestByUser);

// Initialize counters
let highRisk = 0;
let mediumRisk = 0;
let lowRisk = 0;
let noneRisk = 0;
const highRiskNames = [];
const mediumRiskNames = [];

// Aggregate using health_status
for (const company of unique) {
  const status = (company.healthstatus || company.health_status || '').trim();
  const name = company.companyname || company.company_name || 'Unknown Company';

  if (status === 'Poor Health') {
    highRisk++;
    highRiskNames.push(name);
  } else if (status === 'Needs Attention') {
    mediumRisk++;
    mediumRiskNames.push(name);
  } else if (status === 'Good Health') {
    lowRisk++;
  } else if (status === 'Safe' || status === 'None' || status === '') {
    noneRisk++;
  }
}

const total = unique.length;
const dateStr = new Date().toISOString().split('T')[0];

return [
  {
    json: {
      report_date: dateStr,
      total_scanned: total,
      stats: {
        high: highRisk,
        medium: mediumRisk,
        low: lowRisk,
        safe: noneRisk
      },
      high_risk_list: highRiskNames.sort(),
      medium_risk_list: mediumRiskNames.sort()
    }
  }
];

